	ctx    context.Context
	svcCtx *svc.ServiceContext
	logx.Logger
}

func NewLeaveSceneByCentreLogic(ctx context.Context, svcCtx *svc.ServiceContext) *LeaveSceneByCentreLogic {
	return &LeaveSceneByCentreLogic{
		ctx:    ctx,
		svcCtx: svcCtx,
		Logger: logx.WithContext(ctx),
	}
}

// Centre 请求玩家离开场景（或切换场景前的离开）
func (l *LeaveSceneByCentreLogic) LeaveSceneByCentre(in *scene_manager.LeaveSceneByCentreRequest) (*base.Empty, error) {
	// 1. Handle Change Scene State
	changeInfo, err := logic.GetChangeSceneInfo(l.ctx, l.svcCtx, in.PlayerId)
	if err == nil && changeInfo != nil {
		if changeInfo.State == logic.ChangeSceneState_PendingLeave {
			// Update to WaitingEnter
			logic.UpdateChangeSceneState(l.ctx, l.svcCtx, in.PlayerId, logic.ChangeSceneState_WaitingEnter)
		}
	}

	// 2. Clean up player resources (memory cleanup would happen here)

	l.Logger.Infof("Player %d left scene %d on node %s", in.PlayerId, in.SceneId, l.svcCtx.Config.NodeID)

	return &base.Empty{}, nil
}

