		if err != nil {
			l.Logger.Errorf("Failed to clear change scene info: %v", err)
		}
	}

	// 3. Update Player Location
	err = l.svcCtx.Redis.Set(fmt.Sprintf("player:%d:scene", in.PlayerId), fmt.Sprintf("%d", in.SceneId))
	if err != nil {
		l.Logger.Errorf("Failed to update player scene: %v", err)
	}
	err = l.svcCtx.Redis.Set(fmt.Sprintf("player:%d:node", in.PlayerId), l.svcCtx.Config.NodeID)
	if err != nil {
		l.Logger.Errorf("Failed to update player node: %v", err)
	}

	l.Logger.Infof("Player %d entered scene %d on node %s", in.PlayerId, in.SceneId, l.svcCtx.Config.NodeID)

	return &scene_manager.EnterSceneByCentreResponse{ErrorCode: 0}, nil
}

