149. 
150. 	auto& scenePlayers = tlsRegistryManager.sceneRegistry.get_or_emplace<ScenePlayers>(param.scene);
151. 	scenePlayers.emplace(param.enter);
152. 	if (tlsRegistryManager.actorRegistry.any_of<SceneEntityComp>(param.enter))
153. 	{
154. 		LOG_FATAL << tlsRegistryManager.actorRegistry.get_or_emplace<Guid>(param.enter);
155. 	}
156. 	tlsRegistryManager.actorRegistry.emplace<SceneEntityComp>(param.enter, param.scene);
157. 
