175. 	if (!param.CheckValid()) {
176. 		LOG_ERROR << "Invalid parameters when leaving scene";
177. 		return;
178. 	}
179. 
180. 	if (!tlsRegistryManager.actorRegistry.valid(param.leaver)) {
181. 		LOG_ERROR << "Invalid player entity when leaving scene - Player GUID: " << entt::to_integral(param.leaver);
182. 		return;
183. 	}
184. 
185. 	auto sceneEntityComp = tlsRegistryManager.actorRegistry.try_get<SceneEntityComp>(param.leaver);
186. 	if (nullptr == sceneEntityComp)
187. 	{
188. 		LOG_ERROR << "SceneEntityComp not found for player when leaving scene - Player : " << entt::to_integral(param.leaver);
189. 		return;
190. 	}
191. 
192. 	auto sceneEntity = sceneEntityComp->sceneEntity;
193. 	if (!tlsRegistryManager.sceneRegistry.valid(sceneEntity)) {
194. 		LOG_ERROR << "Invalid scene entity when leaving scene - Player : " << entt::to_integral(param.leaver);
195. 		return;
196. 	}
197. 
198. 	BeforeLeaveScene beforeLeaveScene;
199. 	beforeLeaveScene.set_entity(entt::to_integral(param.leaver));
200. 	dispatcher.trigger(beforeLeaveScene);
201. 
202. 	auto& scenePlayers = tlsRegistryManager.sceneRegistry.get<ScenePlayers>(sceneEntity);
203. 	scenePlayers.erase(param.leaver);
204. 	tlsRegistryManager.actorRegistry.remove<SceneEntityComp>(param.leaver);
205. 
206. 	auto* gsPlayerInfo = tlsRegistryManager.sceneRegistry.try_get<SceneNodePlayerStatsPtrPbComponent>(sceneEntity);
207. 	if (gsPlayerInfo) {
208. 		(*gsPlayerInfo)->set_player_size((*gsPlayerInfo)->player_size() - 1);
209. 	}
210. 
211. 	/*AfterLeaveScene afterLeaveScene;
212. 	afterLeaveScene.set_entity(entt::to_integral(param.leaver));
213. 	dispatcher.trigger(afterLeaveScene);*/
214. 
215. 	if (tlsRegistryManager.actorRegistry.any_of<Guid>(param.leaver)) {
216. 		LOG_INFO << "Player left scene - Player GUID: " << tlsRegistryManager.actorRegistry.get_or_emplace<Guid>(param.leaver) << ", Scene ID: " << entt::to_integral(sceneEntity);
217. 	}
218. }
