222. 		LOG_ERROR << "Invalid parameters for destroying scene";
223. 		return;
224. 	}
225. 
226. 	auto* pServerComp = tlsNodeContextManager.GetRegistry(eNodeType::SceneNodeService).try_get<SceneRegistryComp>(param.node);
227. 	if (!pServerComp) {
228. 		LOG_ERROR << "ServerComp not found for node";
229. 		return;
230. 	}
231. 
232. 	auto* sceneInfo = tlsRegistryManager.sceneRegistry.try_get<SceneInfoPBComponent>(param.scene);
233. 	if (!sceneInfo) {
234. 		LOG_ERROR << "SceneInfo not found for scene";
235. 		return;
236. 	}
237. 
238. 	OnSceneDestroyed sceneDestroyedEvent;
239. 	sceneDestroyedEvent.set_entity(entt::to_integral(param.scene));
240. 	dispatcher.trigger(sceneDestroyedEvent);
241. 
242. 	pServerComp->RemoveScene(param.scene);
243. 
244. 	LOG_INFO << "Destroyed scene with ID: " << sceneInfo->guid();
245. }
