248. entt::entity SceneCommon::CreateSceneOnSceneNode(const CreateSceneOnNodeSceneParam& param) {
249. 	if (!param.CheckValid()) {
250. 		LOG_ERROR << "Invalid parameters for creating scene";
251. 		return entt::null;
252. 	}
253. 
254. 	SceneInfoPBComponent sceneInfo(param.sceneInfo);
255. 	if (sceneInfo.guid() <= 0) {
256. 		sceneInfo.set_guid(SceneCommon::GenSceneGuid());
257. 	}
258. 
259. 	const auto scene = CreateEntityIfNotExists(tlsRegistryManager.sceneRegistry, entt::entity{ sceneInfo.guid() });
260. 	if (scene == entt::null) {
261. 		LOG_ERROR << "Failed to create scene in registry";
262. 		return entt::null;
263. 	}
264. 
265. 	tlsRegistryManager.sceneRegistry.emplace<SceneInfoPBComponent>(scene, std::move(sceneInfo));
266. 	tlsRegistryManager.sceneRegistry.emplace<ScenePlayers>(scene);
267. 
268. 	auto& registry = tlsNodeContextManager.GetRegistry(eNodeType::SceneNodeService);
269. 	auto* serverPlayerInfo = registry.try_get<SceneNodePlayerStatsPtrPbComponent>(param.node);
270. 	if (serverPlayerInfo) {
271. 		tlsRegistryManager.sceneRegistry.emplace<SceneNodePlayerStatsPtrPbComponent>(scene, *serverPlayerInfo);
272. 	}
273. 
274. 	auto* pServerComp = registry.try_get<SceneRegistryComp>(param.node);
275. 	if (pServerComp) {
276. 		pServerComp->AddScene(scene);
277. 	}
278. 
279. 	OnSceneCreated createSceneEvent;
280. 	createSceneEvent.set_entity(entt::to_integral(scene));
281. 	dispatcher.trigger(createSceneEvent);
282. 
283. 	LOG_INFO << "Created new scene with ID: " << tlsRegistryManager.sceneRegistry.get<SceneInfoPBComponent>(scene).guid();
284. 	return scene;
285. }

