259. 
260. 	// 3. 设置基本组件
261. 	tlsRegistryManager.actorRegistry.emplace<Player>(player);
262. 	tlsRegistryManager.actorRegistry.emplace<Guid>(player, playerId);
263. 
264. 	// 4. 反序列化全量数据
265. 	PlayerAllDataMessageFieldsUnMarshal(player, playerAllData);
266. 
267. 	// 5. 初始化必要数据（仅首次注册时）
268. 	if (playerAllData.player_database_data().uint64_pb_component().registration_timestamp() <= 0)
