208. void PlayerLifecycleSystem::HandleCrossZoneTransfer(entt::entity playerEntity)
209. {
210. 	auto changeInfo = tlsRegistryManager.actorRegistry.try_get<ChangeSceneInfoPBComponent>(playerEntity);
211. 	if (!changeInfo)
212. 	{
213. 		return;
214. 	}
215. 
216. 	if (!changeInfo->is_cross_zone())
217. 	{
218. 		return;
219. 	}
220. 	
221. 	auto playerId = tlsRegistryManager.actorRegistry.get_or_emplace<Guid>(playerEntity);
222. 
223. 	auto& sessionSnapshot = tlsRegistryManager.actorRegistry.get_or_emplace<PlayerSessionSnapshotPBComp>(playerEntity);
224. 	auto& nodeIdMap = *sessionSnapshot.mutable_node_id();
225. 
226. 	PlayerAllData playerAllDataMessage;
227. 	PlayerAllDataMessageFieldsMarshal(playerEntity, playerAllDataMessage);
228. 	playerAllDataMessage.mutable_player_database_data()->set_player_id(playerId);
229. 	playerAllDataMessage.mutable_player_database_1_data()->set_player_id(playerId);
230. 
231. 	PlayerMigrationPbEvent request;
232. 	request.set_player_id(playerId);
233. 	request.set_from_zone(GetZoneId());
234. 	request.set_to_zone(changeInfo->to_zone_id());
235. 	request.mutable_scene_info()->CopyFrom(*changeInfo);
236. 	request.set_serialized_player_data(std::move(playerAllDataMessage.SerializeAsString()));
237. 	request.set_centre_node_id(nodeIdMap[eNodeType::CentreNodeService]);
238. 
239. 	KafkaProducer::Instance().send("player_migrate", request.SerializeAsString(), std::to_string(playerId), changeInfo->to_zone_id());
240. 
241. 	LOG_INFO << "[CrossZone] Sent player transfer to zone " << changeInfo->to_zone_id() << ": " << playerId;
242. 
243. 	PlayerTipSystem::SendToPlayer(playerEntity, kSceneTransferInProgress, {});
244. 
245. 	tlsRegistryManager.actorRegistry.remove<ChangeSceneInfoPBComponent>(playerEntity);
246. }
