32. void PlayerLifecycleSystem::HandlePlayerAsyncLoaded(Guid playerId, const PlayerAllData& message, const std::any& extra)
33. {
34. 	LOG_INFO << "HandlePlayerAsyncLoaded: Loading player " << playerId;
35. 	
36. 	if (extra.type() == typeid(PlayerSceneEnterContext))
37. 	{
