43. 		}
44. 	}
45. 	else if (extra.type() == typeid(PlayerGameNodeEnteryInfoPBComponent))
46. 	{
47. 		const auto& enterInfo = std::any_cast<PlayerGameNodeEnteryInfoPBComponent>(extra);
48. 		InitPlayerFromAllData(message, enterInfo);
