251. 		LOG_ERROR << "Parse failed for player migration data";
252. 		return;
253. 	}
254. 
255. 	PlayerGameNodeEnteryInfoPBComponent enterInfo; // 已在消息中带上
256. 	enterInfo.set_centre_node_id(msg.centre_node_id());
257. 
258. 	auto player = InitPlayerFromAllData(playerAllDataMessage, enterInfo);
259. 	SavePlayerToRedis(player);
260. }
