262. entt::entity PlayerLifecycleSystem::InitPlayerFromAllData(const PlayerAllData& playerAllData, const PlayerGameNodeEnteryInfoPBComponent& enterInfo)
263. {
264. 	auto playerId = playerAllData.player_database_data().player_id();
265. 
266. 	LOG_INFO << "[InitPlayerFromAllData] Init player: " << playerId;
267. 
268. 	// 1. 创建实体
269. 	auto player = tlsRegistryManager.actorRegistry.create();
270. 
271. 	// 2. 注册全局玩家实体映射
272. 	if (const auto [it, inserted] = tlsPlayerList.emplace(playerId, player); !inserted)
273. 	{
274. 		LOG_ERROR << "[InitPlayerFromAllData] Player already exists in GlobalPlayerList: " << playerId;
275. 		return entt::null;
276. 	}
277. 
278. 	// 3. 设置基本组件
279. 	tlsRegistryManager.actorRegistry.emplace<Player>(player);
280. 	tlsRegistryManager.actorRegistry.emplace<Guid>(player, playerId);
281. 
282. 	// 4. 反序列化全量数据
283. 	PlayerAllDataMessageFieldsUnMarshal(player, playerAllData);
284. 
285. 	// 5. 初始化必要数据（仅首次注册时）
286. 	if (playerAllData.player_database_data().uint64_pb_component().registration_timestamp() <= 0)
287. 	{
288. 		tlsRegistryManager.actorRegistry.get_or_emplace<PlayerUint64PBComponent>(player).set_registration_timestamp(TimeSystem::NowSecondsUTC());
289. 		tlsRegistryManager.actorRegistry.get_or_emplace<LevelPbComponent>(player).set_level(1);
290. 
291. 		RegisterPlayerEvent registerPlayer;
292. 		registerPlayer.set_actor_entity(entt::to_integral(player));
293. 		dispatcher.trigger(registerPlayer);
294. 	}
295. 
296. 	// 6. 设置视野
297. 	tlsRegistryManager.actorRegistry.emplace<ViewRadius>(player).set_radius(10);
298. 
299. 	// 7. 设置玩家节点映射（如 Centre NodeId）
300. 	auto& sessionSnapshot = tlsRegistryManager.actorRegistry.get_or_emplace<PlayerSessionSnapshotPBComp>(player);
301. 	auto& nodeIdMap = *sessionSnapshot.mutable_node_id();
302. 	nodeIdMap[eNodeType::CentreNodeService] = enterInfo.centre_node_id();
303. 
304. 	LOG_INFO << "[InitPlayerFromAllData] Set CentreNodeId: " << enterInfo.centre_node_id();
305. 
306. 	// 8. 初始化系统组件事件
307. 	InitializeActorComponentsEvent initActorEvent;
308. 	initActorEvent.set_actor_entity(entt::to_integral(player));
309. 	dispatcher.trigger(initActorEvent);
310. 
311. 	InitializePlayerComponentsEvent initPlayerEvent;
312. 	initPlayerEvent.set_actor_entity(entt::to_integral(player));
313. 	dispatcher.trigger(initPlayerEvent);
314. 
315. 	// 9. 进入场景节点
316. 	EnterScene(player, enterInfo);
317. 
318. 	return player;
319. }
