321. void PlayerLifecycleSystem::SavePlayerToRedis(entt::entity player)
322. {
323. 	if (!tlsRegistryManager.actorRegistry.valid(player))
324. 	{
325. 		LOG_ERROR << "[SavePlayerToRedis] Invalid player entity";
326. 		return;
327. 	}
328. 
329. 	auto playerId = tlsRegistryManager.actorRegistry.get_or_emplace<Guid>(player);
330. 
331. 	using SaveMessage = PlayerDataRedis::element_type::MessageValuePtr;
332. 	SaveMessage message = std::make_shared<SaveMessage::element_type>();
333. 
334. 	PlayerAllDataMessageFieldsMarshal(player, *message);
335. 
336. 	tlsRedisSystem.GetPlayerDataRedis()->Save(message, playerId);
337. 
338. 	LOG_INFO << "[SavePlayerToRedis] Player " << playerId << " saved to Redis";
339. }
